mapper.select:
SELECT p.*, m.nickname, m.my_team_code AS teamCode FROM locker_posts p JOIN members m ON p.member_id = m.member_id WHERE 1=1
AND p.category = #{category}
ORDER BY p.created_at DESC LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE team_contents
SET
    like_count = like_count + #{likeInc},
    sad_count = sad_count + #{sadInc},
    angry_count = angry_count + #{angryInc}
WHERE content_id = #{contentId}
